<script setup lang="ts">
import{BookHeart,CalendarHeart,Check,Heart,HeartHandshake,History,LoaderCircle,PenLine,Sparkles,WandSparkles}from'@lucide/vue'
import type{AiSavedWork}from'~/composables/useHeartAi'
const{dailyQuestion,dailyAnswers,myAnswer,bothAnswered,aiLoading,generate,loadWorks,saveWork}=useHeartAi()
const answer=ref('');async function saveAnswer(){}
const tab=ref<'date'|'diary'|'letter'>('date'),error=ref(''),material=ref(''),city=ref(''),budget=ref('200元'),preferences=ref('轻松、浪漫、可以拍照'),workDate=ref(new Date().toISOString().slice(0,10)),length=ref(400),recipient=ref('亲爱的'),style=ref('真诚温柔'),saving=ref(false),works=ref<AiSavedWork[]>([])
const results=reactive({date:'',diary:'',letter:''}),saved=reactive({date:false,diary:false,letter:false}),expandedWork=ref('')
const result=computed({get:()=>results[tab.value],set:value=>results[tab.value]=value})
onMounted(async()=>{try{await refreshWorks()}catch(e:any){error.value=e.message}})
async function refreshWorks(){try{works.value=await loadWorks()}catch(e:any){if(!String(e.message).includes('ai_saved_works'))error.value=e.message}}
function changeTab(value:typeof tab.value){tab.value=value;error.value=''}
async function run(feature:string,payload:Record<string,unknown>){error.value='';result.value='';saved[tab.value]=false;try{result.value=await generate(feature,payload)}catch(e:any){error.value=e.message}}
async function makeDate(){await run('date_plan',{city:city.value,budget:budget.value,preferences:preferences.value,time:'半天'})}
async function makeWriting(){await run(tab.value==='diary'?'diary':'love_letter',{material:material.value,length:length.value,style:style.value,recipient:recipient.value})}
async function saveWriting(){if(!result.value)return;saving.value=true;error.value='';try{const kind=tab.value==='date'?'date_plan':tab.value==='diary'?'diary':'love_letter';const title=kind==='date_plan'?`${city.value||'我们的'}约会计划`:kind==='diary'?`${workDate.value} 的 AI 日记`:`写给 ${recipient.value} 的情书`;await saveWork(kind,result.value,workDate.value,title);saved[tab.value]=true;await refreshWorks()}catch(e:any){error.value=String(e.message).includes('ai_saved_works')?'AI 作品库需要升级':e.message}finally{saving.value=false}}
const visibleWorks=computed(()=>{const kind=tab.value==='date'?'date_plan':tab.value==='diary'?'diary':'love_letter';return works.value.filter(x=>x.kind===kind).slice(0,6)})
</script>
<template><section class="heart-ai"><header><div><p class="eyebrow">HEART AI · XIAOMI MIMO</p><h1>心动 AI</h1><span>把灵感变成真正能保存的约会、日记与情书。</span></div><i><WandSparkles :size="25"/></i></header><nav><button :class="{active:tab==='today'}" @click="changeTab('today')"><Heart :size="17"/>今日问题</button><button :class="{active:tab==='date'}" @click="changeTab('date')"><CalendarHeart :size="17"/>约会策划</button><button :class="{active:tab==='diary'}" @click="changeTab('diary')"><BookHeart :size="17"/>AI 日记</button><button :class="{active:tab==='letter'}" @click="changeTab('letter')"><HeartHandshake :size="17"/>AI 情书</button></nav>
<div v-if="tab==='today'" class="today-card workspace"><div v-if="aiLoading&&!dailyQuestion" class="state"><LoaderCircle class="spin"/>正在准备今日问题</div><template v-else-if="dailyQuestion"><small>TODAY'S QUESTION</small><h2>{{dailyQuestion.question}}</h2><div v-if="!myAnswer" class="answer"><textarea v-model="answer" rows="5" placeholder="写下你的答案……"/><button @click="saveAnswer">提交答案</button></div><div v-else-if="!bothAnswered" class="waiting"><Heart fill="currentColor"/><b>答案已经珍藏，等待 TA 回答</b></div><div v-else class="answers"><article v-for="item in dailyAnswers" :key="item.id"><b>{{item.userId===myAnswer?.userId?'我的答案':'TA 的答案'}}</b><p>{{item.answer}}</p></article></div></template></div>
<div v-else class="workspace maker"><aside><template v-if="tab==='date'"><h2>安排一次值得期待的约会</h2><label>城市<input v-model="city" placeholder="例如：上海"/></label><label>预算<input v-model="budget"/></label><label>偏好<textarea v-model="preferences" rows="4"/></label><button :disabled="aiLoading" @click="makeDate"><LoaderCircle v-if="aiLoading" class="spin"/><Sparkles v-else/>生成精简计划</button></template><template v-else><h2>{{tab==='diary'?'把今天写成一篇日记':'写一封只给 TA 的情书'}}</h2><div class="two-fields"><label>保存日期<input v-model="workDate" type="date"/></label><label>生成字数<select v-model="length"><option :value="200">约 200 字</option><option :value="400">约 400 字</option><option :value="600">约 600 字</option><option :value="800">约 800 字</option></select></label></div><div v-if="tab==='letter'" class="two-fields"><label>称呼<input v-model="recipient"/></label><label>语气<select v-model="style"><option>真诚温柔</option><option>浪漫热烈</option><option>自然日常</option><option>克制深情</option></select></label></div><label>{{tab==='diary'?'今天发生了什么？':'你想对 TA 表达什么？'}}<textarea v-model="material" rows="7" placeholder="提供真实细节，AI 不会虚构你没有写过的经历。"/></label><button :disabled="aiLoading||!material.trim()" @click="makeWriting"><LoaderCircle v-if="aiLoading" class="spin"/><PenLine v-else/>生成{{tab==='diary'?'日记':'情书'}}</button></template></aside><main><div class="result-head"><div><small>AI DRAFT</small><h3>{{result?'生成结果':'等待你的灵感'}}</h3></div><span v-if="result">{{result.length}} 字</span></div><div class="result-body"><div v-if="aiLoading" class="state"><LoaderCircle class="spin"/>MiMo 正在认真写作，通常需要十几秒</div><p v-else-if="result">{{result}}</p><div v-else class="empty"><WandSparkles :size="35"/><span>生成内容会显示在这里，切换标签后也会保留。</span></div></div><footer v-if="result" class="save-bar"><span v-if="saved[tab]"><Check :size="16"/>内容已安全保存</span><button :disabled="saving||saved[tab]" @click="saveWriting"><LoaderCircle v-if="saving" class="spin"/><Check v-else/>{{saved[tab]?'保存成功':tab==='date'?'保存约会方案':tab==='diary'?'保存为今日日记':'保存这封情书'}}</button></footer></main></div>
<section v-if="tab!=='today'" class="history"><h3><History :size="18"/>已保存的{{tab==='date'?'约会方案':tab==='diary'?'日记':'情书'}} <small>{{visibleWorks.length}} 篇</small></h3><div v-if="visibleWorks.length"><article v-for="work in visibleWorks" :key="work.id" :class="{expanded:expandedWork===work.id}" role="button" tabindex="0" @click="expandedWork=expandedWork===work.id?'':work.id" @keydown.enter="expandedWork=expandedWork===work.id?'':work.id"><small>{{work.workDate}}</small><b>{{work.title}}</b><p>{{work.content}}</p><button type="button">{{expandedWork===work.id?'收起内容':'展开全文'}}</button></article></div><div v-else class="history-empty"><CalendarHeart v-if="tab==='date'" :size="28"/><BookHeart v-else-if="tab==='diary'" :size="28"/><HeartHandshake v-else :size="28"/><b>还没有保存的{{tab==='date'?'约会方案':tab==='diary'?'日记':'情书'}}</b><span>在上方生成后，点击醒目的保存按钮。</span></div></section><p v-if="error" class="error">{{error}}</p></section></template>
<style scoped>
.heart-ai{width:100%;min-height:calc(100vh - 44px);padding:clamp(22px,3vw,40px);border:1px solid #fff;border-radius:32px;background:linear-gradient(145deg,rgba(255,251,255,.96),rgba(243,228,249,.94),rgba(255,232,242,.94));box-shadow:0 24px 70px rgba(83,47,97,.12)}header{display:flex;justify-content:space-between;align-items:center}header h1{margin:0;color:#4c2e56;font-size:38px}header>div>span{color:#89738e;font-size:13px}header>i{display:grid;place-items:center;width:58px;height:58px;border-radius:20px;background:linear-gradient(135deg,#e2c3f8,#f9cadc);color:#743e8e}nav{display:flex;gap:7px;width:max-content;max-width:100%;margin:26px 0 18px;padding:6px;border-radius:20px;background:rgba(255,255,255,.55);overflow:auto}nav button{display:flex;align-items:center;gap:7px;min-height:42px;padding:0 16px;border:0;border-radius:15px;background:transparent;color:#88748d;white-space:nowrap}nav button.active{background:#fff;color:#7b438e;box-shadow:0 8px 22px rgba(102,57,117,.09)}.workspace{height:min(610px,calc(100vh - 245px));min-height:470px;border:1px solid rgba(255,255,255,.86);border-radius:28px;background:rgba(255,255,255,.58);backdrop-filter:blur(18px)}.maker{display:grid;grid-template-columns:minmax(300px,.8fr) minmax(380px,1.2fr);overflow:hidden}.maker>aside{padding:30px;overflow:auto;border-right:1px solid #eadfed}.maker h2{margin:0 0 24px;color:#523658;font-size:23px}.maker label{display:block;margin:0 0 15px;color:#705b75;font-size:11px;font-weight:750}.maker input,.maker textarea,.maker select,.answer textarea{display:block;width:100%;margin-top:7px;padding:13px 15px;border:1px solid #e5d7e8;border-radius:16px;background:rgba(255,255,255,.85);outline:0;font:inherit;font-size:12px}.maker textarea{resize:vertical}.two-fields{display:grid;grid-template-columns:1fr 1fr;gap:10px}.maker aside>button,.answer button{display:flex;align-items:center;justify-content:center;gap:8px;width:100%;min-height:48px;border:0;border-radius:19px;background:linear-gradient(135deg,#8c