den;margin:0;color:#89788d;font-size:9px;line-height:1.6;-webkit-line-clamp:3;-webkit-box-orient:vertical}.error{padding:13px;border-radius:14px;background:#ffe4ed;color:#b74d73;font-size:11px}.spin{animation:spin 1s linear infinite}@keyframes spin{to{transform:rotate(360deg)}}@media(max-width:760px){.heart-ai{padding:18px 12px;border-radius:24px}header h1{font-size:30px}.workspace{height:auto;min-height:500px}.maker{grid-template-columns:1fr}.maker>aside{border-right:0;border-bottom:1px solid #eadfed}.maker>main{height:520px;padding:20px}.two-fields{grid-template-columns:1fr 1fr}.history>div{grid-template-columns:1fr}.today-card{padding:26px 16px}}
</style>
